from flask import Flask, request, jsonify
from prometheus_client import Counter, Gauge, Histogram, generate_latest, REGISTRY, CollectorRegistry
from prometheus_client import make_wsgi_app
from werkzeug.middleware.dispatcher import DispatcherMiddleware
import time
import random
from functools import wraps

app = Flask(__name__)

app.wsgi_app = DispatcherMiddleware(app.wsgi_app, {
    '/metrics': make_wsgi_app()
})

REQUEST_COUNT = Counter(
    'app_request_count',
    'Total number of requests',
    ['method', 'endpoint', 'status']
)

REQUEST_LATENCY = Histogram(
    'app_request_latency_seconds',
    'Request latency in seconds',
    ['method', 'endpoint'],
    buckets=(0.01, 0.05, 0.1, 0.5, 1.0, 2.5, 5.0, 10.0)
)

ACTIVE_REQUESTS = Gauge(
    'app_active_requests',
    'Number of active requests being processed'
)

BUSINESS_ORDERS = Counter(
    'business_orders_total',
    'Total number of orders placed',
    ['product_category']
)

BUSINESS_ORDER_VALUE = Histogram(
    'business_order_value_dollars',
    'Order value in dollars',
    buckets=(10, 50, 100, 250, 500, 1000, 5000)
)

BUSINESS_INVENTORY = Gauge(
    'business_inventory_items',
    'Current inventory level',
    ['product_id', 'warehouse']
)

BUSINESS_USERS_ONLINE = Gauge(
    'business_users_online',
    'Number of users currently online'
)

ERRORS_TOTAL = Counter(
    'app_errors_total',
    'Total number of application errors',
    ['error_type']
)

DB_QUERY_DURATION = Histogram(
    'db_query_duration_seconds',
    'Database query duration',
    ['query_type'],
    buckets=(0.001, 0.005, 0.01, 0.05, 0.1, 0.5, 1.0)
)

CACHE_HITS = Counter(
    'cache_hits_total',
    'Total number of cache hits',
    ['cache_name']
)

CACHE_MISSES = Counter(
    'cache_misses_total',
    'Total number of cache misses',
    ['cache_name']
)


def track_metrics(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        ACTIVE_REQUESTS.inc()
        start_time = time.time()
        
        try:
            response = f(*args, **kwargs)
            status = response[1] if isinstance(response, tuple) else 200
            REQUEST_COUNT.labels(
                method=request.method,
                endpoint=request.endpoint or 'unknown',
                status=status
            ).inc()
            
            return response
        except Exception as e:
            ERRORS_TOTAL.labels(error_type=type(e).__name__).inc()
            REQUEST_COUNT.labels(
                method=request.method,
                endpoint=request.endpoint or 'unknown',
                status=500
            ).inc()
            raise
        finally:
            latency = time.time() - start_time
            REQUEST_LATENCY.labels(
                method=request.method,
                endpoint=request.endpoint or 'unknown'
            ).observe(latency)
            ACTIVE_REQUESTS.dec()
    
    return decorated_function


def simulate_db_query(query_type='select'):
    start = time.time()
    time.sleep(random.uniform(0.001, 0.1))
    duration = time.time() - start
    DB_QUERY_DURATION.labels(query_type=query_type).observe(duration)


def simulate_cache_access(cache_name='redis'):
    if random.random() > 0.3:
        CACHE_HITS.labels(cache_name=cache_name).inc()
        return True
    else:
        CACHE_MISSES.labels(cache_name=cache_name).inc()
        return False


@app.route('/')
@track_metrics
def index():
    return jsonify({
        'status': 'healthy',
        'message': 'Flask Prometheus Metrics Demo'
    })


@app.route('/api/order', methods=['POST'])
@track_metrics
def create_order():
    data = request.get_json() or {}
    
    product_category = data.get('category', 'electronics')
    order_value = data.get('value', random.uniform(10, 1000))
    
    BUSINESS_ORDERS.labels(product_category=product_category).inc()
    BUSINESS_ORDER_VALUE.observe(order_value)
    
    simulate_cache_access('redis')
    simulate_db_query('insert')
    
    return jsonify({
        'order_id': random.randint(1000, 9999),
        'status': 'created',
        'value': order_value
    }), 201


@app.route('/api/inventory/<product_id>')
@track_metrics
def get_inventory(product_id):
    cache_hit = simulate_cache_access('memcached')
    
    if not cache_hit:
        simulate_db_query('select')
    
    warehouse = request.args.get('warehouse', 'main')
    inventory_level = random.randint(0, 1000)
    
    BUSINESS_INVENTORY.labels(
        product_id=product_id,
        warehouse=warehouse
    ).set(inventory_level)
    
    return jsonify({
        'product_id': product_id,
        'warehouse': warehouse,
        'inventory': inventory_level
    })


