@app.route('/api/batch-orders', methods=['POST'])
@track_metrics
def batch_orders():
    data = request.get_json() or {}
    orders = data.get('orders', [])
    
    for order in orders:
        category = order.get('category', 'general')
        value = order.get('value', 100)
        
        BUSINESS_ORDERS.labels(product_category=category).inc()
        BUSINESS_ORDER_VALUE.observe(value)
    
    simulate_db_query('insert')
    
    return jsonify({
        'processed': len(orders),
        'status': 'success'
    })


